## 1. Playwright Visual Comparison
```typescript
// e2e/visual-regression.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Visual Regression', () => {
  test.describe('Page Layouts', () => {
    const viewports = [
      { width: 1280, height: 720, name: 'desktop' },
      { width: 768, height: 1024, name: 'tablet' },
      { width: 375, height: 667, name: 'mobile' },
    ];

    const pages = [
      { path: '/', name: 'home' },
      { path: '/corpus', name: 'corpus-index' },
      { path: '/method', name: 'method' },
      { path: '/glossary', name: 'glossary' },
    ];

    for (const viewport of viewports) {
      for (const page of pages) {
        test(`${page.name} at ${viewport.name}`, async ({ page: pw }) => {
          await pw.setViewportSize(viewport);
          await pw.goto(page.path);
          await pw.waitForLoadState('networkidle');

          // Wait for any animations to complete
          await pw.waitForTimeout(500);

          await expect(pw).toHaveScreenshot(
            `${page.name}-${viewport.name}.png`,
            {
              maxDiffPixels: 100,
              threshold: 0.1,
            }
          );
        });
      }
    }
  });

  test.describe('Component States', () => {
    test('button states', async ({ page }) => {
      await page.goto('/method');

      const button = page.getByRole('button').first();

      // Default state
      await expect(button).toHaveScreenshot('button-default.png');

      // Hover state
      await button.hover();
      await expect(button).toHaveScreenshot('button-hover.png');

      // Focus state
      await button.focus();
      await expect(button).toHaveScreenshot('button-focus.png');
    });

    test('search open state', async ({ page }) => {
      await page.goto('/corpus');
      await page.keyboard.press('Meta+k');
      await page.waitForSelector('[data-testid="spotlight-search"]');

      await expect(page).toHaveScreenshot('search-open.png', {
        mask: [page.locator('[data-testid="search-results"]')], // Mask dynamic content
      });
    });
  });

  test.describe('Dark Mode', () => {
    test.use({ colorScheme: 'dark' });

    test('corpus page in dark mode', async ({ page }) => {
      await page.goto('/corpus');
      await expect(page).toHaveScreenshot('corpus-dark.png');
    });
  });
});
```

## 2. Baseline Management
```bash
# Generate initial baselines
bun run test:visual --update-snapshots

# Review and commit baselines
git add e2e/*.png
git commit -m "feat(tests): add visual regression baselines"
```

## 3. CI Configuration
```yaml
# .github/workflows/visual.yml
name: Visual Regression
on: [pull_request]

jobs:
  visual:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Install dependencies
        run: bun install

      - name: Run visual tests
        run: bun run test:visual

      - name: Upload diff report
        if: failure()
        uses: actions/upload-artifact@v3
        with:
          name: visual-diff
          path: |
            test-results/
            playwright-report/
```

## 4. PR Comment Bot
```yaml
# Add to visual workflow
- name: Comment PR with diff
  if: failure()
